    debugPrint(message);
  }

  void logHttpRequest(String method, String url, dynamic body) {
    log("HTTP Request: $method $url\nPayload: ${body.toString()}");
  }

  void logHttpResponse(String url, http.Response response) {
    log("HTTP Response: $url\nStatus Code: ${response.statusCode}\nBody: ${response.body}");
